const input = $input.first().json;
const stage = String(input.stage || '').trim().toLowerCase();

const validStages = [
  'create_job', 'process_application', 'evaluate_assessment',
  'schedule_interview', 'interview_feedback', 'final_selection', 'onboarding'
];

if (!validStages.includes(stage)) {
  throw new Error(`Invalid stage: ${stage}. Use one of: ${validStages.join(', ')}`);
}

const out = { ...input, stage };

if (stage === 'create_job') {
  if (!String(out.job_title || '').trim()) throw new Error('create_job requires job_title');
}

if (stage === 'process_application') {
  if (!String(out.candidate_name || '').trim()) throw new Error('process_application requires candidate_name');
  if (!String(out.candidate_email || '').trim()) throw new Error('process_application requires candidate_email');
  if (!String(out.resume_text || '').trim()) throw new Error('process_application requires resume_text');
  if (!String(out.job_title || '').trim() && !String(out.job_id || '').trim()) {
    throw new Error('process_application requires job_title or job_id');
  }
}

if (stage === 'evaluate_assessment') {
  if (!String(out.candidate_id || '').trim()) out.candidate_id = `cand_${Date.now()}`;
  if (!String(out.assessment_answers || '').trim()) {
    out.assessment_answers = 'Sample answers: Q1) Used PostgreSQL indexing. Q2) Built n8n automations.';
  }
  if (!String(out.job_title || '').trim()) out.job_title = 'Open Role';
}

if (stage === 'schedule_interview') {
  if (!String(out.candidate_email || '').trim()) throw new Error('schedule_interview requires candidate_email');
  if (!String(out.candidate_name || '').trim()) out.candidate_name = 'Candidate';
  if (!String(out.job_title || '').trim()) out.job_title = 'Open Role';
}

if (stage === 'interview_feedback') {
  if (!String(out.candidate_id || '').trim()) out.candidate_id = `cand_${Date.now()}`;
  if (!out.interview_feedback || typeof out.interview_feedback !== 'object' || !Object.keys(out.interview_feedback).length) {
    out.interview_feedback = { technical: 4, communication: 5, culture: 4 };
  }
  if (!String(out.candidate_name || '').trim()) out.candidate_name = 'Candidate';
}

if (stage === 'final_selection') {
  if (!String(out.candidate_id || '').trim()) out.candidate_id = `cand_${Date.now()}`;
  if (!String(out.candidate_name || '').trim()) out.candidate_name = 'Candidate';
  if (!String(out.candidate_email || '').trim()) out.candidate_email = 'candidate@example.com';
  if (!String(out.job_title || '').trim()) out.job_title = 'Open Role';
  if (!out.offer_details || typeof out.offer_details !== 'object') {
    out.offer_details = { salary: out.salary_range || 'TBD', start_date: '2026-06-01' };
  }
}

if (stage === 'onboarding') {
  if (!String(out.candidate_email || '').trim()) throw new Error('onboarding requires candidate_email');
  if (!String(out.candidate_name || '').trim()) out.candidate_name = 'New Hire';
  if (!String(out.job_title || '').trim()) out.job_title = 'Open Role';
  if (!String(out.department || '').trim()) out.department = 'General';
}

return [{
  json: {
    ...out,
    run_id: `hr_${Date.now()}_${Math.random().toString(16).slice(2, 8)}`,
    processed_at: new Date().toISOString()
  }
}];

const cleanKey = (key) => String(key || '').trim().replace(/^Bearer\s+/i, '');
async function getOpenRouterKey(payload) {
  let apiKey = cleanKey(payload.openrouter_api_key);
  if (!apiKey) {
    try {
      const cred = await this.getCredentials('httpHeaderAuth');
      apiKey = cleanKey(cred.value || cred.headerValue);
    } catch (e) {}
  }
  if (!apiKey) throw new Error('Missing openrouter_api_key in payload or HTTP Header Auth credential.');
  return apiKey;
}

const payload = $input.first().json;
const apiKey = await getOpenRouterKey.call(this, payload);
const model = payload.openrouter_model || 'openai/gpt-4o-mini';
const jobId = payload.job_id || `job_${Date.now()}`;

let description = String(payload.job_description || '').trim();
if (!description) {
  const systemPrompt = 'You are an expert HR copywriter. Return strict JSON with keys: title, summary, responsibilities, requirements, benefits.';
  const userPrompt = `Create a job posting for: ${payload.job_title}\nDepartment: ${payload.department}\nLocation: ${payload.location}\nType: ${payload.employment_type}\nRequired skills: ${(payload.required_skills || []).join(', ')}\nNice to have: ${(payload.nice_to_have_skills || []).join(', ')}\nMin experience: ${payload.min_experience_years} years\nSalary: ${payload.salary_range}`;
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://openrouter.ai/api/v1/chat/completions',
    headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json', 'X-Title': 'HR Recruitment Agent' },
    body: { model, temperature: 0.3, response_format: { type: 'json_object' }, messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]},
    json: true,
    timeout: 60000
  });
  const raw = response.choices?.[0]?.message?.content;
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  description = JSON.stringify(parsed, null, 2);
}

return [{
  json: {
    ...payload,
    job_id: jobId,
    job_opening: {
      job_id: jobId,
      title: payload.job_title,
      department: payload.department,
      location: payload.location,
      employment_type: payload.employment_type,
      headcount: payload.headcount,
      hiring_manager: payload.hiring_manager,
      description,
      status: 'open',
      created_at: new Date().toISOString()
    }
  }
}];

const item = $input.first().json;
const hooks = item.publish_webhooks || {};
const platforms = ['linkedin', 'indeed', 'naukri', 'careers_page'];
const results = [];

for (const platform of platforms) {
  const url = String(hooks[platform] || '').trim();
  if (!url) {
    results.push({ platform, status: 'skipped', reason: 'no_webhook_configured' });
    continue;
  }
  if (item.dry_run !== false) {
    results.push({ platform, status: 'dry_run', url });
    continue;
  }
  try {
    await this.helpers.httpRequest({
      method: 'POST', url,
      body: {
        job_id: item.job_id,
        title: item.job_title,
        location: item.location,
        description: item.job_opening?.description,
        published_at: new Date().toISOString()
      },
      json: true, timeout: 30000
    });
    results.push({ platform, status: 'published' });
  } catch (err) {
    results.push({ platform, status: 'failed', error: err?.message || 'request_failed' });
  }
}

return [{ json: { ...item, publish_results: results } }];

const item = $input.first().json;
const filePath = `/files/hr-jobs-${item.job_id}.json`;
const payload = {
  run_id: item.run_id,
  stage: item.stage,
  job_opening: item.job_opening,
  publish_results: item.publish_results,
  stored_at: new Date().toISOString()
};
const content = JSON.stringify(payload, null, 2);

return [{
  json: {
    ...item,
    storage: { type: 'file', path: filePath },
    job_file_path: filePath
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: `hr-jobs-${item.job_id}.json`
    }
  }
}];

const item = $input.first().json;
const text = String(item.resume_text || '');
const emailMatch = text.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
const phoneMatch = text.match(/(\+?\d[\d\s().-]{7,}\d)/);
const yearsMatch = text.match(/(\d+)\+?\s*years?/i);

const parsed = {
  raw_length: text.length,
  inferred_email: emailMatch ? emailMatch[0] : item.candidate_email,
  inferred_phone: phoneMatch ? phoneMatch[0] : item.candidate_phone,
  inferred_experience_years: yearsMatch ? Number(yearsMatch[1]) : null,
  skills_mentioned: (item.required_skills || []).filter((s) => text.toLowerCase().includes(String(s).toLowerCase())),
  parsed_at: new Date().toISOString()
};

const candidateId = item.candidate_id || `cand_${Date.now()}_${Math.random().toString(16).slice(2, 6)}`;

return [{ json: { ...item, candidate_id: candidateId, resume_parsed: parsed } }];

const cleanKey = (key) => String(key || '').trim().replace(/^Bearer\s+/i, '');
async function getOpenRouterKey(payload) {
  let apiKey = cleanKey(payload.openrouter_api_key);
  if (!apiKey) {
    try {
      const cred = await this.getCredentials('httpHeaderAuth');
      apiKey = cleanKey(cred.value || cred.headerValue);
    } catch (e) {}
  }
  if (!apiKey) throw new Error('Missing openrouter_api_key in payload or HTTP Header Auth credential.');
  return apiKey;
}

const item = $input.first().json;
const apiKey = await getOpenRouterKey.call(this, item);
const model = item.openrouter_model || 'openai/gpt-4o-mini';
const rp = item.resume_parsed || {};

const systemPrompt = 'You are a senior technical recruiter. Return strict JSON with keys: overall_score (0-100), skills_match_score, experience_match_score, culture_fit_score, strengths, gaps, recommendation (shortlist|reject|review), summary, red_flags (array).';
const userPrompt = `Job: ${item.job_title}\nRequired: ${(item.required_skills || []).join(', ')}\nNice-to-have: ${(item.nice_to_have_skills || []).join(', ')}\nMin years: ${item.min_experience_years}\n\nCandidate: ${item.candidate_name}\nResume:\n${item.resume_text}\n\nParsed skills found: ${(rp.skills_mentioned || []).join(', ')}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://openrouter.ai/api/v1/chat/completions',
  headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json', 'X-Title': 'HR Recruitment Agent' },
  body: { model, temperature: 0.2, response_format: { type: 'json_object' }, messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]},
  json: true,
  timeout: 60000
});

const raw = response.choices?.[0]?.message?.content;
const screening = typeof raw === 'string' ? JSON.parse(raw) : raw;
const score = Number(screening.overall_score || 0);
const threshold = Number(item.shortlist_threshold || 70);
const decision = score >= threshold && String(screening.recommendation || '').toLowerCase() !== 'reject'
  ? 'shortlist'
  : 'reject';

return [{
  json: {
    ...item,
    ai_screening: { ...screening, model: response.model || model, screened_at: new Date().toISOString() },
    candidate_score: score,
    pipeline_decision: decision
  }
}];

const item = $input.first().json;
const s = item.ai_screening || {};
return [{
  json: {
    ...item,
    candidate_record: {
      candidate_id: item.candidate_id,
      job_id: item.job_id || null,
      job_title: item.job_title,
      name: item.candidate_name,
      email: item.candidate_email,
      phone: item.candidate_phone,
      source: item.source,
      score: item.candidate_score,
      decision: item.pipeline_decision,
      screening: s,
      resume_parsed: item.resume_parsed,
      status: item.pipeline_decision === 'shortlist' ? 'shortlisted' : 'rejected',
      updated_at: new Date().toISOString()
    }
  }
}];

const item = $input.first().json;
const filePath = `/files/hr-candidate-${item.candidate_id}.json`;
const content = JSON.stringify(item.candidate_record, null, 2);

const dbUrl = String(item.database_webhook_url || '').trim();
let dbResult = { status: 'skipped' };
if (dbUrl && !item.dry_run) {
  try {
    await this.helpers.httpRequest({
      method: 'POST', url: dbUrl,
      body: { table: 'candidates', record: item.candidate_record },
      json: true, timeout: 30000
    });
    dbResult = { status: 'stored', target: 'webhook' };
  } catch (err) {
    dbResult = { status: 'failed', error: err?.message };
  }
} else if (dbUrl && item.dry_run) {
  dbResult = { status: 'dry_run', target: dbUrl };
}

return [{
  json: {
    ...item,
    storage: { file: filePath, database: dbResult },
    candidate_file_path: filePath
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: `hr-candidate-${item.candidate_id}.json`
    }
  }
}];

const item = $input.first().json;
const url = String(item.assessment_url || 'https://variphi.com/assessments').trim();
const subject = `Assessment for ${item.job_title} — ${item.candidate_name}`;
const html = `<p>Hi ${item.candidate_name},</p><p>Congratulations — you have been shortlisted for <strong>${item.job_title}</strong>.</p><p>Please complete your technical assessment: <a href="${url}">${url}</a></p><p>Score: ${item.candidate_score}/100</p><p>Regards,<br/>HR Team</p>`;
return [{ json: { ...item, email_outbound: { to: item.candidate_email, cc: item.hr_email, subject, html, type: 'assessment_invite' } } }];

const item = $input.first().json;
const subject = `Update on your application — ${item.job_title}`;
const html = `<p>Hi ${item.candidate_name},</p><p>Thank you for applying for <strong>${item.job_title}</strong>. After review, we will not be moving forward at this time.</p><p>Regards,<br/>HR Team</p>`;
return [{ json: { ...item, email_outbound: { to: item.candidate_email, cc: item.hr_email, subject, html, type: 'rejection' } } }];

const cleanKey = (key) => String(key || '').trim().replace(/^Bearer\s+/i, '');
async function getOpenRouterKey(payload) {
  let apiKey = cleanKey(payload.openrouter_api_key);
  if (!apiKey) {
    try {
      const cred = await this.getCredentials('httpHeaderAuth');
      apiKey = cleanKey(cred.value || cred.headerValue);
    } catch (e) {}
  }
  if (!apiKey) throw new Error('Missing openrouter_api_key in payload or HTTP Header Auth credential.');
  return apiKey;
}

const item = $input.first().json;
const apiKey = await getOpenRouterKey.call(this, item);
const model = item.openrouter_model || 'openai/gpt-4o-mini';
const systemPrompt = 'You are an assessment evaluator. Return strict JSON: score (0-100), passed (boolean), strengths, weaknesses, recommendation (proceed_interview|reject|review), feedback_summary.';
const userPrompt = `Job: ${item.job_title}\nCandidate: ${item.candidate_name || item.candidate_id}\nAnswers:\n${item.assessment_answers}`;

const response = await this.helpers.httpRequest({
  method: 'POST', url: 'https://openrouter.ai/api/v1/chat/completions',
  headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json', 'X-Title': 'HR Recruitment Agent' },
  body: { model, temperature: 0.2, response_format: { type: 'json_object' }, messages: [
    { role: 'system', content: systemPrompt }, { role: 'user', content: userPrompt }
  ]},
  json: true, timeout: 60000
});
const raw = response.choices?.[0]?.message?.content;
const evaluation = typeof raw === 'string' ? JSON.parse(raw) : raw;
const passed = Boolean(evaluation.passed);
const proceed = String(evaluation.recommendation || '').toLowerCase() === 'proceed_interview' || passed;
const subject = proceed
  ? `Assessment passed — next step for ${item.job_title}`
  : `Assessment update — ${item.job_title}`;
const html = proceed
  ? `<p>Hi ${item.candidate_name || 'Candidate'},</p><p>Your assessment results are in. Score: ${evaluation.score ?? 'n/a'}/100. We would like to proceed to the interview stage.</p><p>Summary: ${evaluation.feedback_summary || ''}</p>`
  : `<p>Hi ${item.candidate_name || 'Candidate'},</p><p>Thank you for completing the assessment. We will not be moving forward at this time.</p><p>Summary: ${evaluation.feedback_summary || ''}</p>`;

return [{
  json: {
    ...item,
    assessment_evaluation: evaluation,
    assessment_passed: passed,
    pipeline_decision: proceed ? 'proceed_interview' : 'reject',
    email_outbound: item.candidate_email ? { to: item.candidate_email, cc: item.hr_email, subject, html, type: 'assessment_result' } : undefined
  }
}];

const item = $input.first().json;
const slot = item.interview_slot || new Date(Date.now() + 3 * 24 * 60 * 60 * 1000).toISOString();
const calUrl = String(item.calendar_webhook_url || '').trim();
let calendar = { status: 'pending', slot };

if (calUrl && !item.dry_run) {
  try {
    const res = await this.helpers.httpRequest({
      method: 'POST', url: calUrl,
      body: {
        candidate_name: item.candidate_name,
        candidate_email: item.candidate_email,
        job_title: item.job_title,
        interview_slot: slot,
        attendees: [item.candidate_email, item.hr_email].filter(Boolean)
      },
      json: true, timeout: 30000
    });
    calendar = { status: 'scheduled', slot, response: res };
  } catch (err) {
    calendar = { status: 'failed', error: err?.message, slot };
  }
} else if (calUrl) {
  calendar = { status: 'dry_run', slot, url: calUrl };
}

const notifyHtml = `<p>Interview scheduled for <strong>${item.candidate_name}</strong> — ${item.job_title}</p><p>Slot: ${slot}</p>`;
return [{
  json: {
    ...item,
    interview: calendar,
    email_outbound: {
      to: item.candidate_email,
      cc: item.hr_email,
      subject: `Interview scheduled — ${item.job_title}`,
      html: notifyHtml,
      type: 'interview_scheduled'
    }
  }
}];

const item = $input.first().json;
const fb = item.interview_feedback || {};
const ratings = Object.values(fb).filter((v) => typeof v === 'number');
const avg = ratings.length ? ratings.reduce((a, b) => a + b, 0) / ratings.length : null;
const hireRecommendation = avg !== null && avg >= 4 ? 'hire' : avg !== null && avg >= 3 ? 'maybe' : 'no_hire';
const summary = {
  average_rating: avg,
  recommendation: hireRecommendation,
  raw: fb,
  collected_at: new Date().toISOString()
};

const html = `<p>Interview feedback recorded for <strong>${item.candidate_name || item.candidate_id}</strong>.</p><p>Average rating: ${avg ?? 'n/a'}</p><p>Recommendation: ${hireRecommendation}</p>`;

return [{
  json: {
    ...item,
    feedback_summary: summary,
    pipeline_decision: hireRecommendation,
    email_outbound: item.hr_email ? {
      to: item.hr_email,
      cc: item.sender_email || item.hr_email,
      subject: `Interview feedback — ${item.candidate_name || item.candidate_id}`,
      html,
      type: 'interview_feedback_internal'
    } : undefined
  }
}];

