const apiKey = await getOpenRouterKey.call(this, item);
const model = item.openrouter_model || 'openai/gpt-4o-mini';
const offer = item.offer_details || {};
const systemPrompt = 'You are an HR operations specialist. Return strict JSON: offer_letter_markdown, start_date_suggestion, onboarding_checklist (array of strings).';
const userPrompt = `Generate offer letter for ${item.candidate_name}, role ${item.job_title}, salary ${offer.salary || item.salary_range}, start ${offer.start_date || 'TBD'}, location ${item.location}.`;

const response = await this.helpers.httpRequest({
  method: 'POST', url: 'https://openrouter.ai/api/v1/chat/completions',
  headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json', 'X-Title': 'HR Recruitment Agent' },
  body: { model, temperature: 0.3, response_format: { type: 'json_object' }, messages: [
    { role: 'system', content: systemPrompt }, { role: 'user', content: userPrompt }
  ]},
  json: true, timeout: 60000
});
const raw = response.choices?.[0]?.message?.content;
const offerDoc = typeof raw === 'string' ? JSON.parse(raw) : raw;
const html = `<p>Hi ${item.candidate_name},</p><p>We are pleased to extend an offer for <strong>${item.job_title}</strong>.</p><pre>${offerDoc.offer_letter_markdown || ''}</pre>`;
return [{
  json: {
    ...item,
    offer: offerDoc,
    pipeline_decision: 'hired',
    email_outbound: {
      to: item.candidate_email,
      cc: item.hr_email,
      subject: `Offer Letter — ${item.job_title}`,
      html,
      type: 'offer_letter'
    }
  }
}];

const cleanKey = (key) => String(key || '').trim().replace(/^Bearer\s+/i, '');
async function getOpenRouterKey(payload) {
  let apiKey = cleanKey(payload.openrouter_api_key);
  if (!apiKey) {
    try {
      const cred = await this.getCredentials('httpHeaderAuth');
      apiKey = cleanKey(cred.value || cred.headerValue);
    } catch (e) {}
  }
  if (!apiKey) throw new Error('Missing openrouter_api_key in payload or HTTP Header Auth credential.');
  return apiKey;
}

const item = $input.first().json;
const apiKey = await getOpenRouterKey.call(this, item);
const model = item.openrouter_model || 'openai/gpt-4o-mini';
const systemPrompt = 'Return strict JSON: onboarding_tasks (array of {owner, task, due_days}), welcome_email_html.';
const userPrompt = `Create onboarding plan for new hire ${item.candidate_name}, role ${item.job_title}, department ${item.department}, start in IT and HR.`;

const response = await this.helpers.httpRequest({
  method: 'POST', url: 'https://openrouter.ai/api/v1/chat/completions',
  headers: { Authorization: `Bearer ${apiKey}`, 'Content-Type': 'application/json', 'X-Title': 'HR Recruitment Agent' },
  body: { model, temperature: 0.3, response_format: { type: 'json_object' }, messages: [
    { role: 'system', content: systemPrompt }, { role: 'user', content: userPrompt }
  ]},
  json: true, timeout: 60000
});
const raw = response.choices?.[0]?.message?.content;
const plan = typeof raw === 'string' ? JSON.parse(raw) : raw;
return [{
  json: {
    ...item,
    onboarding_plan: plan,
    email_outbound: {
      to: item.candidate_email,
      cc: item.hr_email,
      subject: `Welcome aboard — ${item.job_title}`,
      html: plan.welcome_email_html || `<p>Welcome ${item.candidate_name}!</p>`,
      type: 'onboarding_welcome'
    }
  }
}];

const item = $input.first().json;
const SMTP_DOMAIN = 'variphi.com';
const DEFAULT_SENDER = 'information@variphi.com';

const isDomainEmail = (value) => {
  const email = String(value || '').trim().toLowerCase();
  if (!email.includes('@')) return false;
  return email.split('@')[1] === SMTP_DOMAIN;
};

const resolveSender = () => {
  const candidates = [item.sender_email, item.hr_email];
  for (const value of candidates) {
    if (isDomainEmail(value)) return String(value).trim();
  }
  return DEFAULT_SENDER;
};

const sender = resolveSender();
const hrCc = isDomainEmail(item.hr_email) ? String(item.hr_email).trim() : sender;
const outbound = item.email_outbound || {};
const to = String(outbound.to || item.candidate_email || '').trim();

if (!to) {
  throw new Error('Missing recipient email. Set email_outbound.to or candidate_email.');
}

return [{
  json: {
    ...item,
    sender_email: sender,
    hr_email: hrCc,
    email_sent: false,
    email_outbound: {
      ...outbound,
      to,
      from: sender,
      cc: outbound.cc || hrCc
    }
  }
}];

const item = $input.first().json;
const lines = [
  `✅ HR Recruitment — ${item.stage || 'update'}`,
  `Run: ${item.run_id || 'n/a'}`,
];
if (item.job_id) lines.push(`Job: ${item.job_id}${item.job_title ? ' — ' + item.job_title : ''}`);
if (item.candidate_id || item.candidate_name) {
  lines.push(`Candidate: ${item.candidate_name || item.candidate_id}`);
}
if (item.candidate_score != null) lines.push(`Score: ${item.candidate_score}/100`);
if (item.pipeline_decision) lines.push(`Decision: ${item.pipeline_decision}`);
if (item.assessment_passed != null) lines.push(`Assessment passed: ${item.assessment_passed}`);
if (item.job_opening?.title) lines.push(`Opening created: ${item.job_opening.title}`);
if (item.email_sent) lines.push('Email: sent');
return [{ json: { ...item, telegram_text: lines.join('\n').slice(0, 4000) } }];

const item = $json;
const token = String(item.telegram_bot_token || '').trim();
const chatId = String(item.telegram_chat_id || '').trim();
let telegram_delivery = { status: 'skipped', reason: 'disabled_or_missing_credentials' };

if (item.notify_telegram && token && chatId) {
  const text = String(item.telegram_text || '').trim();
  if (!text) {
    telegram_delivery = { status: 'skipped', reason: 'empty_message' };
  } else {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: `https://api.telegram.org/bot${token}/sendMessage`,
        body: { chat_id: chatId, text },
        json: true,
        timeout: 30000,
      });
      if (!resp?.ok) throw new Error(resp?.description || 'Telegram API returned ok:false');
      telegram_delivery = {
        status: 'sent',
        message_id: resp.result?.message_id || null,
        chat_id: chatId,
      };
    } catch (err) {
      telegram_delivery = { status: 'failed', error: String(err?.message || err).slice(0, 500) };
    }
  }
}

return [{ json: { ...item, telegram_delivery, telegram_sent: telegram_delivery.status === 'sent' } }];
